SELECT function_name 
FROM functions 
WHERE function_id = 1;

SELECT models.model_name, reports.report_type
FROM models
INNER JOIN reports ON models.model_id = reports.model_id;

SELECT model_id, function_id
FROM user_access
WHERE user_id = 'specific_user_id';

SELECT DISTINCT u.user_name
FROM users u
INNER JOIN user_access ua ON u.user_id = ua.user_id;

SELECT * 
FROM models 
WHERE model_id > 5;

SELECT AVG(execution_time) AS average_execution_time
FROM phases
WHERE last_executed_at > '2023-05-01 00:00:00';

SELECT users.user_name
FROM users
WHERE users.user_id IN (
  SELECT DISTINCT anomalies.detected_by
  FROM anomalies
);
